def search_words(words):
    res=[]
    for i, field, text in hadith_texts:
        if not text:
            continue
        norm_text = normalize_ar(text)
        ok=True
        for w in words:
            if normalize_ar(w) not in norm_text:
                ok=False
                break
        if ok:
            res.append((i, field, text))
    return res

